#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int jobScheduling(int N, int D[], int P[]) {
        vector<pair<int, int>> jobs;
        for (int i = 0; i < N; i++) {
            jobs.push_back({D[i], P[i]});
        }
        sort(jobs.begin(), jobs.end(), [](const auto& a, const auto& b) {
            return a.second > b.second;
        });
        int max_deadline = 0;
        for (int i = 0; i < N; i++) {
            max_deadline = max(max_deadline, D[i]);
        }
        vector<bool> slots(max_deadline + 1, false);
        int profit = 0;
        for (const auto& job : jobs) {
            for (int i = job.first; i > 0; i--) {
                if (!slots[i]) {
                    slots[i] = true;
                    profit += job.second;
                    break;
                }
            }
        }
        return profit;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    cin >> N;
    int D[N], P[N];
    for (int i = 0; i < N; i++) cin >> D[i];
    for (int i = 0; i < N; i++) cin >> P[i];
    Solution sol;
    int ans = sol.jobScheduling(N, D, P);
    cout << ans << '\n';
    return 0;
}
